// Filter new reviews since last check
const reviews = $input.item.json.result.reviews || [];
const lastCheckTime = $('Setup Variables').item.json.last_check_timestamp;
const currentTime = Math.floor(Date.now() / 1000);

// Filter reviews newer than last check
const newReviews = reviews.filter(review => {
  return review.time > lastCheckTime;
});

// Update last check timestamp
const setupVars = $('Setup Variables').item.json;
setupVars.last_check_timestamp = currentTime;

return newReviews.map(review => ({
  ...review,
  place_id: setupVars.place_id,
  business_name: setupVars.business_name
}));

// Parse AI response and classify sentiment
const aiResponse = $input.item.json.response;

// Extract sentiment score (1-5) and response draft from AI
const lines = aiResponse.split('\n');
let sentimentScore = 3;
let responseDraft = '';

lines.forEach(line => {
  if (line.startsWith('SENTIMENT:')) {
    sentimentScore = parseInt(line.replace('SENTIMENT:', '').trim());
  }
  if (line.startsWith('RESPONSE:')) {
    responseDraft = line.replace('RESPONSE:', '').trim();
  }
});

// Combine with original review data
const review = $('Filter New Reviews').item.json;

return {
  ...review,
  sentiment_score: sentimentScore,
  ai_response_draft: responseDraft,
  is_negative: sentimentScore < 3,
  created_at: new Date().toISOString()
};

